oxy_webhelp_navlinks = {"azr_sql_db_config_rbk_backup-d27243e19008":{"topics":[{"title":"Mapping Azure SQL DB account to Exocompute subscription","shortdesc":"<p class=\"shortdesc\">Map your Azure cloud account for protecting Azure SQL Databases to an Exocompute host         subscription. This task links your database environment to the data processing resources         needed for backups, preparing the environment for creating an archival location and securing         your data with Rubrik backups.<\/p>","href":"saas\/azr_sql_db_mapping_acc_exo_subs.html","attributes":{"data-id":"azr_sql_db_mapping_acc_exo_subs"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_mapping_acc_exo_subs-d27243e19019","topics":[]},{"title":"Upgrading TDE with CMK for Azure SQL DB","shortdesc":"<p class=\"shortdesc\">Existing cloud accounts need a one-time upgrade to enable Transparent Data Encryption         (TDE) with Customer-Managed Key (CMK) support and update subscription settings with a         User-assigned Managed Identity (UMI). <\/p>","href":"saas\/azr_sql_db_upgrading_tde_cmk.html","attributes":{"data-id":"azr_sql_db_upgrading_tde_cmk"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_upgrading_tde_cmk-d27243e19030","topics":[]},{"title":"Creating a custom SLA Domain for Azure SQL DB","shortdesc":"<p class=\"shortdesc\">Create a custom SLA Domain for Azure SQL Databases to streamline and customize         workload protection and management policies.<\/p>","href":"saas\/azr_sql_db_creating_custom_sla.html","attributes":{"data-id":"azr_sql_db_creating_custom_sla"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_creating_custom_sla-d27243e19041","topics":[]}]}};